private RealMatrix squareRoot(RealMatrix m) {
    final RealMatrix sqrtMatrix = m.copy();
    for (int i = 0; i < sqrtMatrix.getRowDimension(); i++) {
        sqrtMatrix.multiplyEntry(i, i, Math.sqrt(sqrtMatrix.getEntry(i, i)));
    }
    return sqrtMatrix;
}

